pub(crate) fn translate_fr(en: &str) -> &str {
    lookup_fr(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_fr(en: &str) -> bool {
    lookup_fr(en).is_some()
}

